INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0204313N$$, 2027, $$T-AGOS are Ocean surveillance ships that gather underwater acoustical data to support the Integrated Undersea Surveillance System (IUSS) mission by providing a
ship platform capable of theater anti-submarine passive and active acoustic surveillance. T-AGOS ships are operated by Military Sealift Command (MSC) to support
the anti-submarine warfare (ASW) mission of Atlantic and Pacific Fleet Commanders. Both classes of T-AGOS ships use the Surveillance Towed-Array Sensor System
(SURTASS) to gather undersea acoustic data. They also carry electronic equipment to process and transmit that data via satellite to shore stations for evaluation.
Funding in this budget will recapitalize Navy's Auxiliary General Ocean Surveillance (T-AGOS) ships (four T-AGOS 19 Class vessels & one T-AGOS 23 Class vessel)
with a total of seven (7) T-AGOS 25 Class ships based on the 2016 N81 Force Structure Assessment (FSA).$$, $$T-AGOS are ocean surveillance ships that gather underwater acoustical data to support the mission of the Integrated Undersea Surveillance System (IUSS) by providing
a ship platform capable of theater anti-submarine acoustic passive and active surveillance. Auxiliary General Ocean Surveillance Ships (T-AGOS) are operated by
Military Sealift Command to support the anti-submarine warfare mission of the commanders of the Atlantic and Pacific Fleets. The two current classes of surveillance
ships use Surveillance Towed-Array Sensor System (SURTASS) equipment to gather undersea acoustic data. The ships also carry electronic equipment to process and
transmit that data via satellite to shore stations for evaluation. Funding will support recapitalization of the four Small Waterplane Area Twin Hull (SWATH) T-19 Class and
one SWATH T-23 Class.

