INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0206624M$$, 2027, $$This program provides funding for Marine Air-Ground Task Force requirements for Combat Service Support equipment improvement. It will enhance combat breaching
capabilities of the ground combat elements, logistics, maintenance and transportation. The PE also provides improvements in all areas of Combat Service Support
Equipment Vehicles by determining the replacement for the light fleet of vehicles. This includes projects such as: Alternative Power Sources for Communications
Equipment which is a suite of devices that provide the commander with the capability to use existing power to operate his communication equipment, computers and
peripheral equipment instead of using batteries or fossil fuel generators; the Marine Corps Family of Automatic Test Systems, formerly TETS, which provides automatic
testing capability for use by technicians both in garrison and forward edge of the battlefield; improvements in all areas of the LVSR & MTVR; the High Performance
Capabilities for Military Vehicles Project which is dedicated to applying the best practices of the motor sports industry to military vehicles including engineering expertise,
equipment, and technology.

 The FY 2026 spend plan amount for Combat Service Support Engineering Equipment includes $34,905 thousands of discretionary and $10,531 thousands of mandatory
 (reconciliation) for a total of $45,436 thousands.
Systems Development$$, $$The Family of Automatic Test Systems (ATS) provides Marine Corps maintainers with organic test capabilities for both garrison and deployed operations. It supports
condition-based maintenance, equipment diagnostics, and fault isolation on multiple platforms, such as radio test sets intended for littoral environments. In alignment
with Force Design initiatives and Expeditionary Advanced Base Operations (EABO), the ATS funding strategy prioritizes pushing these automatic test capabilities to the
lowest tactical level, enabling units to diagnose and repair equipment as far forward as possible.

 Conditions Based Maintenance (CBM+) is a strategy that leverages data to optimize readiness. The program works by collecting, analyzing, and acting on information
 from both on-platform sensors and historical maintenance records stored in GCSS-MC. To accomplish this, the program outfits platforms with data-logging hardware
 for use in garrison, during Expeditionary Advanced Base Operations (EABO), and in littoral environments. This data is then processed by predictive analytics software,
 which transforms it into actionable insights that enable data-driven solutions to maintenance and supply challenges across all levels of the Marine Corps enterprise.

